import typing, sys
_stdin = sys.stdin.read().split()
_stdin_iter = iter(_stdin)
def I(T: typing.Type):
	return T(next(_stdin_iter))
_stdout: typing.List[str] = []
def O(*oo: typing.Any):
	_stdout.extend(map(str, oo))

class DSU:
	def __init__(self, sz: int) -> None:
		self.pa: typing.List[int] = [-1]*sz # [val]id->[val]id
		self.size: typing.List[int] = [0]*sz # [val]id->[val]size of its subtree
		self.right_most: typing.List[int] = [-1]*sz # [val]id->[val]num

		self.timestamp = [-1]*sz # [val]->[n]
		self.rep: typing.List[int] = [-1]*sz # [val]->[val] the real value of some place in current DSU
	def setup(self, at: int, timestamp: int, realv: int)->None:
		self.pa[at]=at
		self.size[at]=1
		self.right_most[at]=at
		self.timestamp[at]=timestamp
		self.rep[at]=realv
	def find(self, q: int)->int: # id->id
		while(self.pa[q]!=self.pa[self.pa[q]]):
			self.pa[q] = self.pa[self.pa[q]]
		return self.pa[q]
	def merge(self, hi: int, lo: int)->None: # id->
		hi = self.find(hi)
		lo = self.find(lo)
		if self.size[hi] < self.size[lo]:
			hi, lo = lo, hi
		self.pa[lo] = hi
		self.size[hi] += self.size[lo]
		self.right_most[hi] = max(self.right_most[hi], self.right_most[lo])

n = I(int)
_valrange = int(1e6)+2+n #
dsu = DSU(_valrange)
for i in range(n):
	inn = I(int)
	if dsu.find(inn)==-1: # inn is not inside a range
		dsu.setup(inn, i, inn)
		if dsu.find(inn+1)!=-1:
			dsu.merge(inn, inn+1)
		if dsu.find(inn-1)!=-1:
			dsu.merge(inn-1, inn)
	else:
		pos=dsu.right_most[dsu.find(inn)]+1
		dsu.setup(pos, i, inn)
		dsu.merge(pos-1, pos)
		if dsu.find(pos+1)!=-1:
			dsu.merge(pos, pos+1)

fin = [0]*n # [n]->[val]
for v in range(_valrange):
	if dsu.timestamp[v]!=-1:
		# print(dsu.timestamp[v])
		fin[dsu.timestamp[v]] = v

for i in range(n):
	O(fin[i], ' ')
sys.stdout.write(''.join(_stdout))

